#!/bin/bash
set -e
TMPDIR="/home/amax/Desktop/netlab-gpu-exporter"
mkdir -p "${TMPDIR}"
cd "${TMPDIR}"

# Decode files
echo "" | base64 -d > exporter.py
echo "" | base64 -d > install.sh
echo "" | base64 -d > gpu-exporter.service

# Run install with sudo
sudo bash install.sh

echo "==> Remote install complete."
